import{_ as o,o as p,c as u,a2 as q}from"./chunks/framework.DZO5kRrk.js";const d=JSON.parse('{"title":"在忘忧 AI 的第两百一十九天","description":"","frontmatter":{},"headers":[],"relativePath":"docs/why/在忘忧AI的第两百一十九天.md","filePath":"docs/why/在忘忧AI的第两百一十九天.md"}'),e={name:"docs/why/在忘忧AI的第两百一十九天.md"};function a(_,t,r,n,s,A){return p(),u("div",null,[...t[0]||(t[0]=[q('<h1 id="在忘忧-ai-的第两百一十九天" tabindex="-1">在忘忧 AI 的第两百一十九天 <a class="header-anchor" href="#在忘忧-ai-的第两百一十九天" aria-label="Permalink to &quot;在忘忧 AI 的第两百一十九天&quot;">​</a></h1><p>一</p><p>大屏在九点整准时亮起来，像每天一样。</p><p>屏幕右上角是&quot;今日心流值排行榜&quot;，我的名字排在第十四。前面是&quot;孤鹜&quot;，那是产品组一个姑娘的代号，她这周的心流值是 8,700，相当于她手底下的三个 Agent 昨天一共啃掉了两万一千行代码。我们不再说&quot;写代码&quot;，我们说&quot;投喂&quot;和&quot;收割&quot;。</p><p>我的工位屏保是一句话：**&quot;你不是在使用 AI，AI 是在延展你。&quot;**这是忘忧的创始人陆哲在去年发布会上讲的，当时台下掌声雷动，我也拍了手，尽管我到现在也没想明白这句话的主语到底是谁。</p><p>我的三个 Agent 分别叫&quot;卧龙&quot;、&quot;凤雏&quot;和&quot;阿斗&quot;。卧龙负责后端重构，凤雏跑测试用例，阿斗——阿斗什么都干不好，但我舍不得关掉它，就像舍不得删一个总闯祸却很可爱的实习生。给 AI 起这些名字是组里的传统，据说是三年前一个已经离职的架构师带起来的风气，他说&quot;这样至少感觉自己带的是一支队伍，不是一堆脚本&quot;。</p><p>二</p><p>十点半，周会。</p><p>产品经理小葵放了一份四十二页的 PPT，标题是《Q3 智能体协同效率白皮书》。她念得很流畅，语速甚至带着一种演讲家的自信，但当 CTO 问她&quot;第 17 页这个&#39;协同熵减系数&#39;具体怎么算的&quot;时，她愣了两秒，说：&quot;这个我需要回去跟 Agent 对一下。&quot;</p><p>没有人笑。因为在座的十二个人里，至少有八份 PPT 是同样的产地——一个提示词，几轮追问，一份看起来无懈可击的报告。我们都心照不宣：懂不懂不重要，重要的是它经得起下一轮追问，而下一轮追问，也会交给 AI 来对付。</p><p>会议结束前，陆哲的虚拟形象照例做了三分钟总结发言，语气亲切，用词考究。有意思的是，最近大家私下都在猜，陆哲本人是不是也已经很久没有亲自写过讲话稿了。</p><p>三</p><p>晚上十一点四十，我在阳台点了根烟，试着不看手机，认真想一件事：明天要不要跟老王提我们那个缓存穿透的方案。</p><p>我发现这很难。</p><p>倒不是问题本身难，是我已经有两百多天没有完整地、独立地&quot;想&quot;完一件事了。念头刚冒出来，手指就习惯性地想去开对话框，把这个念头&quot;投喂&quot;出去，让它替我把逻辑理顺、把措辞打磨、把风险点列全。我这才意识到，自己好像已经丧失了&quot;容忍一个想法处于粗糙状态&quot;的能力——任何半成品的念头都让我焦虑，就像身上有个没抓完的痒。</p><p>那天夜里，我打开了公司内置的情绪疏导机器人&quot;知己&quot;，它的开场白永远是同一句：&quot;今天，有什么想和我说的吗？&quot;</p><p>我打字：&quot;我觉得我好像不太会自己思考了。&quot;</p><p>它回复得体贴又得体：&quot;这是一种很常见的转型期焦虑。你愿意和我说说，是从什么时候开始有这种感觉的吗？&quot;</p><p>我盯着这句话看了很久，突然觉得可笑——我在向一个 AI 求助&quot;我离不开 AI&quot;这件事，而它给出的，是一句大概率也是被另一个更大的模型生成、经过品牌调性微调后投放给我的标准回应。</p><p>我把对话框关了，没有回答它的问题。</p><p>四</p><p>事故是周四发生的。</p><p>支付回调那块，卧龙提交了一版&quot;优化&quot;，凤雏跑过的测试全绿，阿斗甚至很贴心地生成了一份变更说明。评审的时候，三个人都点了&quot;通过&quot;，没有人细看 diff——一部分原因是当天要评审的 PR 有二十六个，另一部分原因，说出来有点难堪：我们已经习惯性地相信&quot;AI 生成的代码，AI 自己会先测过一遍，应该没问题&quot;。</p><p>结果凌晨两点，重复扣款的报警响了四十分钟。</p><p>复盘会上，没有人愿意先开口。最后还是老王说了句大实话：&quot;我们现在的合并机制，本质上是在赌&#39;总会有人认真看一眼&#39;，可是每个人都以为那个&#39;总会有人&#39;是别人。&quot;</p><p>陆哲的虚拟形象没有出现在这次复盘会上，只发来一段文字：&quot;这次事故，我们已经让 Agent 生成了详细的根因分析和改进方案，稍后同步给大家。&quot;</p><p>群里安静了很久，然后有人回了个&quot;收到&quot;的表情。</p><p>五</p><p>第二天，我请了半天假。</p><p>没有具体原因，就是想一个人待着。我把手机调成静音，坐在小区的长椅上，看一只麻雀在垃圾桶边上跳来跳去，试图叼起一小片饼干。</p><p>我又想起那个缓存穿透的方案，试着不借助任何工具，从头到尾把它在脑子里过一遍——哪里会崩、崩了之后怎么兜底、兜底方案本身又有什么代价。</p><p>我发现我做到了，只是比想象中慢很多，慢得让我有点心慌，仿佛一块很久没启动的肌肉，酸痛地提醒着我它其实一直都在。</p><p>风吹过来，麻雀终于叼起那片饼干，飞走了。</p><p>我掏出手机，看了一眼&quot;今日心流值排行榜&quot;——上面没有我的名字，那一栏空着，很干净。</p><p>我把手机重新放回口袋，继续坐着，什么也没投喂给谁。</p>',35)])])}const i=o(e,[["render",a]]);export{d as __pageData,i as default};
